final class ArrayToDelimitedStringConverter implements ConditionalGenericConverter {

	private final CollectionToDelimitedStringConverter delegate;

	ArrayToDelimitedStringConverter(ConversionService conversionService) {
		this.delegate = new CollectionToDelimitedStringConverter(conversionService);
	}

	@Override
	public Set<ConvertiblePair> getConvertibleTypes() {
		return Collections.singleton(new ConvertiblePair(Object[].class, String.class));
	}

	@Override
	public boolean matches(TypeDescriptor sourceType, TypeDescriptor targetType) {
		return this.delegate.matches(sourceType, targetType);
	}

	@Override
	public Object convert(@Nullable Object source, TypeDescriptor sourceType, TypeDescriptor targetType) {
		List<Object> list = Arrays.asList(ObjectUtils.toObjectArray(source));
		return this.delegate.convert(list, sourceType, targetType);
	}

}

public class McpStreamableServiceImpl implements McpStreamableService, Disposable {

    private volatile DubboMcpStreamableTransportProvider transportProvider = null;

    @Override
    public void streamable(StreamObserver<ServerSentEvent<byte[]>> responseObserver) {
        if (transportProvider == null) {
            synchronized (this) {
                if (transportProvider == null) {
                    transportProvider = getTransportProvider();
                }
            }
        }
        transportProvider.handleRequest(responseObserver);
    }

    public DubboMcpStreamableTransportProvider getTransportProvider() {
        return McpApplicationDeployListener.getDubboMcpStreamableTransportProvider();
    }

    @Override
    public void destroy() {}
}

